import React, { useState } from "react";
import doctorService from "../../services/doctor.service";

const initialForm = {
  userId: "",
  firstName: "",
  lastName: "",
  email: "",
  phoneNumber: "",
  specialty: "",
  qualification: "",
  experienceYears: "",
  bio: "",
  consultationFee: "",
  averageConsultationDuration: ""
};

function DoctorDashboard() {
  const [doctorId, setDoctorId] = useState("");
  const [userIdToSearch, setUserIdToSearch] = useState("");
  const [form, setForm] = useState(initialForm);
  const [doctor, setDoctor] = useState(null);
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const setFeedback = (ok, text) => {
    if (ok) {
      setMessage(text);
      setError("");
    } else {
      setError(text);
      setMessage("");
    }
  };

  const parseForm = () => ({
    ...form,
    userId: Number(form.userId),
    experienceYears: form.experienceYears ? Number(form.experienceYears) : null,
    consultationFee: form.consultationFee ? Number(form.consultationFee) : null,
    averageConsultationDuration: form.averageConsultationDuration
      ? Number(form.averageConsultationDuration)
      : null
  });

  const handleChange = (event) => {
    setForm((prev) => ({ ...prev, [event.target.name]: event.target.value }));
  };

  const handleRegister = async (event) => {
    event.preventDefault();
    setLoading(true);
    try {
      const response = await doctorService.registerDoctor(parseForm());
      setDoctor(response.data);
      setDoctorId(String(response.data.id));
      setFeedback(true, "Doctor profile registered successfully.");
    } catch (err) {
      setFeedback(false, err.response?.data?.message || "Registration failed.");
    } finally {
      setLoading(false);
    }
  };

  const loadDoctorById = async () => {
    if (!doctorId) {
      setFeedback(false, "Enter doctor ID first.");
      return;
    }
    setLoading(true);
    try {
      const response = await doctorService.getDoctorById(doctorId);
      setDoctor(response.data);
      setForm({
        ...initialForm,
        userId: response.data.userId || "",
        firstName: response.data.firstName || "",
        lastName: response.data.lastName || "",
        email: response.data.email || "",
        phoneNumber: response.data.phoneNumber || "",
        specialty: response.data.specialty || "",
        qualification: response.data.qualification || "",
        experienceYears: response.data.experienceYears || "",
        bio: response.data.bio || "",
        consultationFee: response.data.consultationFee || "",
        averageConsultationDuration: response.data.averageConsultationDuration || ""
      });
      setFeedback(true, "Doctor loaded by ID.");
    } catch (err) {
      setFeedback(false, err.response?.data?.message || "Doctor not found.");
    } finally {
      setLoading(false);
    }
  };

  const loadDoctorByUserId = async () => {
    if (!userIdToSearch) {
      setFeedback(false, "Enter user ID first.");
      return;
    }
    setLoading(true);
    try {
      const response = await doctorService.getDoctorByUserId(userIdToSearch);
      setDoctor(response.data);
      setDoctorId(String(response.data.id));
      setFeedback(true, "Doctor loaded by user ID.");
    } catch (err) {
      setFeedback(false, err.response?.data?.message || "Doctor not found for user ID.");
    } finally {
      setLoading(false);
    }
  };

  const handleUpdate = async (event) => {
    event.preventDefault();
    if (!doctorId) {
      setFeedback(false, "Doctor ID is required for update.");
      return;
    }
    setLoading(true);
    try {
      const response = await doctorService.updateDoctorProfile(doctorId, parseForm());
      setDoctor(response.data);
      setFeedback(true, "Doctor profile updated.");
    } catch (err) {
      setFeedback(false, err.response?.data?.message || "Update failed.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <section className="card">
      <h2>Doctor Profile</h2>

      <div className="inline-row">
        <input
          placeholder="Doctor ID"
          value={doctorId}
          onChange={(e) => setDoctorId(e.target.value)}
        />
        <button type="button" onClick={loadDoctorById} disabled={loading}>
          Load by Doctor ID
        </button>
      </div>

      <div className="inline-row">
        <input
          placeholder="User ID"
          value={userIdToSearch}
          onChange={(e) => setUserIdToSearch(e.target.value)}
        />
        <button type="button" onClick={loadDoctorByUserId} disabled={loading}>
          Load by User ID
        </button>
      </div>

      <form onSubmit={handleRegister} className="grid-form">
        {Object.keys(initialForm).map((field) => (
          <input
            key={field}
            name={field}
            placeholder={field}
            value={form[field]}
            onChange={handleChange}
            required={["userId", "firstName", "lastName", "email", "specialty"].includes(field)}
          />
        ))}

        <div className="inline-row">
          <button type="submit" disabled={loading}>
            Register
          </button>
          <button type="button" onClick={handleUpdate} disabled={loading}>
            Update
          </button>
        </div>
      </form>

      {message && <p className="ok">{message}</p>}
      {error && <p className="error">{error}</p>}

      {doctor && (
        <pre className="result">{JSON.stringify(doctor, null, 2)}</pre>
      )}
    </section>
  );
}

export default DoctorDashboard;
